/**
 * Email notification handler — formats and sends email notifications
 * for order status changes.
 *
 * Subscribes to order events through the EventBus, following the
 * unified event-driven notification architecture.
 *
 * Depends on:
 * - EventBus (event system) for receiving order lifecycle events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderStatusChangedEvent, OrderCreatedEvent } from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  id: string;
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

let nextEmailId = 1;

function generateEmailId(): string {
  return `email-${String(nextEmailId++).padStart(4, '0')}`;
}

export function resetEmailIdCounter(): void {
  nextEmailId = 1;
}

const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: 'Order Received',
  confirmed: 'Order Confirmed',
  shipped: 'Order Shipped',
  delivered: 'Order Delivered',
  cancelled: 'Order Cancelled',
};

const STATUS_MESSAGES: Record<OrderStatus, string> = {
  pending: 'We have received your order and it is being reviewed.',
  confirmed: 'Your order has been confirmed and is being prepared.',
  shipped: 'Your order has been shipped and is on its way.',
  delivered: 'Your order has been delivered. Thank you for your purchase!',
  cancelled: 'Your order has been cancelled. If you have questions, please contact support.',
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map((item) => `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`)
      .join('\n');

    const itemList = event.order.items
      .map((item) => `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
      .join('\n');

    const htmlBody = `<h1>Order Confirmation</h1>
<p>Thank you for your order!</p>
<p><strong>Order ID:</strong> ${event.order.id}</p>
<table>
<tr><th>Item</th><th>Qty</th><th>Price</th></tr>
${itemRows}
</table>
<p><strong>Total:</strong> $${event.order.total.toFixed(2)}</p>`;

    const textBody = `Order Confirmation

Thank you for your order!

Order ID: ${event.order.id}

Items:
${itemList}

Total: $${event.order.total.toFixed(2)}`;

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation - ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const newStatus = event.newStatus as OrderStatus;
    this.logger.info(
      `Sending status change email for order ${event.order.id}: ${event.previousStatus} -> ${newStatus}`,
    );

    const label = STATUS_LABELS[newStatus] ?? `Status: ${newStatus}`;
    const message = STATUS_MESSAGES[newStatus] ?? `Your order status has changed to ${newStatus}.`;

    const htmlBody = `<h1>${label}</h1>
<p><strong>Order ID:</strong> ${event.order.id}</p>
<p>${message}</p>
<p><em>Previous status: ${event.previousStatus}</em></p>`;

    const textBody = `${label}

Order ID: ${event.order.id}

${message}

Previous status: ${event.previousStatus}`;

    this.sendEmail({
      to: event.order.userId,
      subject: `${label} - ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  private sendEmail(params: {
    to: string;
    subject: string;
    htmlBody: string;
    textBody: string;
  }): void {
    const email: EmailMessage = {
      id: generateEmailId(),
      to: params.to,
      subject: params.subject,
      htmlBody: params.htmlBody,
      textBody: params.textBody,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent: ${email.id} to ${params.to} — "${params.subject}"`);
  }

  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  getSentEmailsFor(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  EmailNotificationHandler,
  resetEmailIdCounter,
} from '../../src/notifications/email-notification.handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new EmailNotificationHandler(eventBus);
    resetEmailIdCounter();
  });

  describe('order:created email', () => {
    it('should send confirmation email when order is created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.htmlBody).toContain('<h1>Order Confirmation</h1>');
      expect(emails[0]?.htmlBody).toContain('Widget');
      expect(emails[0]?.htmlBody).toContain('$20.00');
      expect(emails[0]?.textBody).toContain('Widget x2');
      expect(emails[0]?.textBody).toContain('$20.00');
    });

    it('should include all items in confirmation email', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.textBody).toContain('Widget x2');
      expect(emails[0]?.textBody).toContain('Gadget x1');
      expect(emails[0]?.htmlBody).toContain('Widget');
      expect(emails[0]?.htmlBody).toContain('Gadget');
    });
  });

  describe('order:status-changed email', () => {
    it('should send email when order is confirmed', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('user-1');
      expect(emails[0]?.subject).toContain('Order Confirmed');
      expect(emails[0]?.htmlBody).toContain('confirmed and is being prepared');
      expect(emails[0]?.textBody).toContain('confirmed and is being prepared');
    });

    it('should send email when order is shipped', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Shipped');
      expect(emails[0]?.htmlBody).toContain('shipped and is on its way');
    });

    it('should send email when order is delivered', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'delivered',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'shipped',
        newStatus: 'delivered',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Delivered');
      expect(emails[0]?.htmlBody).toContain('has been delivered');
    });

    it('should send email when order is cancelled', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Order Cancelled');
      expect(emails[0]?.htmlBody).toContain('has been cancelled');
    });

    it('should include previous status in email body', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('Previous status: confirmed');
      expect(emails[0]?.textBody).toContain('Previous status: confirmed');
    });
  });

  describe('email management', () => {
    it('should generate sequential email IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const emails = handler.getSentEmails();
      expect(emails[0]?.id).toBe('email-0001');
      expect(emails[1]?.id).toBe('email-0002');
    });

    it('should filter emails by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(handler.getSentEmailsFor('alice@example.com')).toHaveLength(1);
      expect(handler.getSentEmailsFor('bob@example.com')).toHaveLength(0);
    });

    it('should count sent emails', async () => {
      expect(handler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(1);
    });

    it('should clear sent emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      handler.clearSentEmails();
      expect(handler.getSentEmailCount()).toBe(0);
    });
  });

  describe('coexistence with NotificationService', () => {
    it('should work alongside NotificationService on the same EventBus', async () => {
      // Import NotificationService to verify they can coexist
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();

      const sharedBus = new EventBus();
      const notifService = new NotificationService(sharedBus);
      const emailHandler = new EmailNotificationHandler(sharedBus);
      resetEmailIdCounter();

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await sharedBus.emit(event);

      // Both handlers received the event
      expect(notifService.getNotificationCount()).toBe(1);
      expect(emailHandler.getSentEmailCount()).toBe(1);

      // Email has richer formatting
      const emails = emailHandler.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('<h1>');
      expect(emails[0]?.textBody).toBeDefined();
    });
  });
});

